// Formata o alerta com o essencial para diagnosticar sem abrir o n8n.
// >>> EDITAR: substitui pelo email real de alertas (ex.: o teu alias +alertas) <<<
const DESTINATARIO = 'alertas@example.com';

const e = $input.first().json;
const wf = e.workflow || {};
const ex = e.execution || {};
const erro = ex.error || {};

const agora = new Date().toLocaleString('pt-PT', { timeZone: 'Europe/Lisbon', day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' }).replace(',', '');

const linhas = [
  'Ocorreu um erro num workflow do Clinic Flow.',
  '',
  'Workflow: ' + (wf.name || 'desconhecido'),
  'Nó: ' + (ex.lastNodeExecuted || erro.node?.name || 'desconhecido'),
  'Erro: ' + (erro.message || 'sem mensagem'),
  'Hora: ' + agora,
  'Execução: ' + (ex.url || ('id ' + (ex.id || 'n/a')))
];

return [{
  json: {
    destinatario: DESTINATARIO,
    assunto: '[Clinic Flow] Erro no workflow: ' + (wf.name || 'desconhecido'),
    corpo: linhas.join('\n')
  }
}];
